#include<bits/stdc++.h>
using namespace std;
long long a[1000010],b[1000010];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        a[i]-=i;
    }
    priority_queue<int> q;
    for(int i=1;i<=n;i++)
    {
        q.push(a[i]);
        q.push(a[i]);
        q.pop();
        b[i]=q.top();
    }
    for(int i=n-1;i>=1;i--)
    {
        b[i]=min(b[i],b[i+1]);
    }
    long long ans=0;
    for(int i=1;i<=n;i++)
    {
        ans+=abs(a[i]-b[i]);
    }
    printf("%lld\n",ans);
    for(int i=1;i<=n;i++)
    {
        printf("%lld\n",b[i]+i);
    }
    return 0;
}
